    @EventHandler(priority = EventPriority.LOW, ignoreCancelled = true) public void onInteractEntity(PlayerInteractEntityEvent e) { Player p = e.getPlayer(); Entity entity = e.getRightClicked(); Material item = p.getInventory().getItemInMainHand().getType(); if (entity instanceof ArmorStand) { String deny = checkFlag(p, entity.getLocation(), Flag.ITEM_USE); if (deny != null) { e.setCancelled(true); p.sendMessage(msg("prefix") + " " + deny); } return; } if (entity instanceof Hanging) { String deny = checkFlag(p, entity.getLocation(), Flag.FRAME); if (deny != null) { e.setCancelled(true); p.sendMessage(msg("prefix") + " " + deny); } return; } if (entity instanceof Tameable tame && tame.isTamed() && tame.getOwner() != null) { if (!tame.getOwner().getUniqueId().equals(p.getUniqueId()) && !pd(p.getUniqueId()).ignoreClaims) { e.setCancelled(true); p.sendMessage(msg("prefix") + " §c这只宠物不是你的！"); } return; } if ((entity instanceof Animals && !(entity instanceof Cow && item == Material.BUCKET) && !(entity instanceof MushroomCow && item == Material.SHEARS)) || entity instanceof Villager || entity instanceof IronGolem || entity instanceof Snowman) { String deny = checkFlag(p, entity.getLocation(), Flag.DAMAGE_ENTITY); if (deny != null) { e.setCancelled(true); p.sendMessage(msg("prefix") + " " + deny); } return; } if (entity instanceof Vehicle && !(entity instanceof Minecart)) { String deny = checkFlag(p, entity.getLocation(), Flag.RIDE); if (deny != null) { e.setCancelled(true); p.sendMessage(msg("prefix") + " " + deny); } return; } if (item == Material.LEAD && !(entity instanceof LeashHitch)) { String deny = checkFlag(p, entity.getLocation(), Flag.ITEM_USE); if (deny != null) { e.setCancelled(true); p.sendMessage(msg("prefix") + " " + deny); } return; } if (item == Material.NAME_TAG) { String deny = checkFlag(p, entity.getLocation(), Flag.ITEM_USE); if (deny != null) { e.setCancelled(true); p.sendMessage(msg("prefix") + " " + deny); } } }

