    @EventHandler(priority = EventPriority.HIGH, ignoreCancelled = true) public void onRedstone(BlockRedstoneEvent e) { long k = (long) e.getBlock().getChunk().getX() << 32 | (e.getBlock().getChunk().getZ() & 0xFFFFFFFFL); if (redstoneCount.merge(k, 1, Integer::sum) > REDSTONE_MAX) e.setNewCurrent(e.getOldCurrent()); }
