    private void checkRent() { long now = System.currentTimeMillis(); for (Claim c : claims.values()) { if (c.rentedTo == null || c.rentEndTime <= 0 || c.rentEndTime > now) continue; Player r = Bukkit.getPlayer(c.rentedTo); if (r != null) r.sendMessage(msg("prefix") + " §c租约已到期！"); Player o = Bukkit.getPlayer(c.owner); if (o != null) o.sendMessage(msg("prefix") + " §e" + c.name + " §e租约到期"); c.removeMember(c.rentedTo); c.rentedTo = null; c.rentedToName = null; c.rentEndTime = 0; } }

