    // ═══════ 进出提示 ═══════
    @EventHandler public void onMove(PlayerMoveEvent e) { Player p = e.getPlayer(); if (e.getFrom().getBlockX() == e.getTo().getBlockX() && e.getFrom().getBlockZ() == e.getTo().getBlockZ()) return; TpTask tp = tpTasks.get(p.getUniqueId()); if (tp != null) { if (Math.abs(e.getTo().getBlockX() - tp.dest.getBlockX()) > 1 || Math.abs(e.getTo().getBlockZ() - tp.dest.getBlockZ()) > 1 || Math.abs(e.getTo().getBlockY() - tp.dest.getBlockY()) > 1) { Bukkit.getScheduler().cancelTask(tp.taskId); tpTasks.remove(p.getUniqueId()); p.sendMessage(msg("prefix") + " §c传送已取消！"); } } if (p.getInventory().getItemInMainHand().getType() == Material.WOODEN_AXE) { Long last = lastParticle.get(p.getUniqueId()); if (last == null || System.currentTimeMillis() - last > 600) { lastParticle.put(p.getUniqueId(), System.currentTimeMillis()); Claim near = getClaimAt(p.getLocation(), null); if (near != null) showClaimParticles(p, near); } } PlayerData d = pd(p.getUniqueId()); if (!d.ignoreClaims) { Claim tc = getClaimAt(e.getTo(), d); if (tc != null && !tc.checkFlag(p.getUniqueId(), Flag.MOVE)) { e.setCancelled(true); return; } if (tc != null && !tc.checkFlag(p.getUniqueId(), Flag.FLY) && (p.isFlying() || p.isGliding())) { p.setFlying(false); p.setGliding(false); p.sendMessage(msg("prefix") + " §c此领地禁止飞行！"); } } Claim at = getClaimAt(e.getTo(), null); String newId = at != null ? at.id : null, oldId = currentClaim.get(p.getUniqueId()); if (Objects.equals(oldId, newId)) return; currentClaim.put(p.getUniqueId(), newId); if (newId != null && oldId == null) { Set<Flag> mf = at.memberFlags.get(p.getUniqueId()); String tag = at.owner.equals(p.getUniqueId()) ? "§a[主人] " : (mf != null ? "§e[成员] " : "§7"); if (!at.enterMsg.isEmpty()) p.sendMessage(Color.colorize(at.enterMsg.replace("%player%", p.getName()).replace("%owner%", at.ownerName).replace("%claim%", at.name))); p.showTitle(Title.title(comp(at.name, NamedTextColor.GREEN), comp(tag + "主人: " + at.ownerName, NamedTextColor.GRAY), Title.Times.times(Duration.ofMillis(400), Duration.ofSeconds(2), Duration.ofMillis(400)))); p.playSound(p.getLocation(), Sound.BLOCK_NOTE_BLOCK_BELL, 0.5f, 1.5f); } else if (newId == null && oldId != null) { Claim old = claims.get(oldId); if (old != null && !old.leaveMsg.isEmpty()) p.sendMessage(Color.colorize(old.leaveMsg.replace("%player%", p.getName()).replace("%owner%", old.ownerName).replace("%claim%", old.name))); p.showTitle(Title.title(comp("§7离开领地"), Component.empty(), Title.Times.times(Duration.ofMillis(300), Duration.ofSeconds(1), Duration.ofMillis(300)))); p.playSound(p.getLocation(), Sound.BLOCK_NOTE_BOCK_BASS, 0.3f, 0.8f); } }
    private void showClaimParticles(Player p, Claim c) { World w = p.getWorld(); if (!w.getName().equals(c.world)) return; int y = p.getLocation().getBlockY(); Particle pt = c.owner.equals(p.getUniqueId()) ? Particle.HAPPY_VILLAGER : (c.memberFlags.containsKey(p.getUniqueId()) ? Particle.COMPOSTER : Particle.DRIPPING_LAVA); for (int x = c.minX; x <= c.maxX; x += 2) { spawnPt(p, pt, x, y, c.minZ); spawnPt(p, pt, x, y, c.maxZ); } for (int z = c.minZ; z <= c.maxZ; z += 2) { spawnPt(p, pt, c.minX, y, z); spawnPt(p, pt, c.maxX, y, z); } for (int dy = -1; dy <= 2; dy++) { spawnPt(p, pt, c.minX, y + dy, c.minZ); spawnPt(p, pt, c.maxX, y + dy, c.minZ); spawnPt(p, pt, c.minX, y + dy, c.maxZ); spawnPt(p, pt, c.maxX, y + dy, c.maxZ); } }
    private void spawnPt(Player p, Particle pt, int x, int y, int z) { p.spawnParticle(pt, x + 0.5, y + 0.5, z + 0.5, 1, 0, 0, 0, 0); }
    private Component comp(String s, NamedTextColor c) { return LegacyComponentSerializer.legacySection().deserialize(s).color(c); }
    private Component comp(String s) { return LegacyComponentSerializer.legacySection().deserialize(s); }

    // ═══════ 命令 ═══════
    class ClaimCmd implements CommandExecutor {
        public boolean onCommand(CommandSender s, Command c, String l, String[] a) { if (!(s instanceof Player p)) { s.sendMessage(msg("player-only")); return true; } if (a.length == 0) { openMainGui(p); return true; } switch (a[0].toLowerCase()) { case "create" -> doCreate(p, a); case "subcreate", "sub" -> doSubCreate(p, a); case "expand" -> doExpand(p, a); case "shrink", "contract" -> doShrink(p, a); case "invite", "trust" -> doInvite(p, a); case "accept" -> doAccept(p, a); case "deny", "reject" -> doDeny(p, a); case "invites" -> doInvites(p); case "kick", "untrust" -> doKick(p, a); case "remove", "delete" -> doRemove(p, a); case "give", "transfer" -> doGive(p, a); case "rename" -> doRename(p, a); case "setmsg" -> doSetmsg(p, a); case "sell" -> doSell(p, a); case "buy" -> doBuy(p, a); case "tp", "home" -> doTp(p, a); case "setspawn" -> doSetspawn(p, a); case "admin" -> doAdmin(p, a); case "list" -> openMainGui(p); case "all" -> doAll(p, a); case "map" -> openMapGui(p); case "shop" -> openBuyGui(p); case "screen", "search" -> doScreen(p, a); case "flag" -> doFlag(p, a); case "info" -> doInfo(p); case "rent" -> doRent(p, a); case "unrent" -> doUnrent(p); case "lease" -> doLease(p, a); case "evict" -> doEvict(p, a); case "setsign" -> doSetSign(p); default -> showHelp(p); } return true; }

        private void doCreate(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim create <名字>"); return; } Location[] sel = selections.get(p.getUniqueId()); if (sel == null || sel[0] == null || sel[1] == null) { p.sendMessage(msg("prefix") + " §c请先手持木斧选区！"); return; } int minX = Math.min(sel[0].getBlockX(), sel[1].getBlockX()), maxX = Math.max(sel[0].getBlockX(), sel[1].getBlockX()), minZ = Math.min(sel[0].getBlockZ(), sel[1].getBlockZ()), maxZ = Math.max(sel[0].getBlockZ(), sel[1].getBlockZ()); int dx = maxX - minX + 1, dz = maxZ - minZ + 1; if (dx > 64 || dz > 64) { p.sendMessage(msg("prefix") + " §c选区不能超过 64x64！"); return; } if (dx < 3 || dz < 3) { p.sendMessage(msg("prefix") + " §c选区最小 3x3！"); return; } if (playerClaims(p.getUniqueId()).size() >= (p.hasPermission("megaplugin.claim.admin") ? 50 : 5)) { p.sendMessage(msg("prefix") + " §c领地已达上限！"); return; } String wname = p.getWorld().getName(); for (Claim cx : claims.values()) { if (!cx.world.equals(wname)) continue; if (!(cx.maxX < minX || cx.minX > maxX || cx.maxZ < minZ || cx.minZ > maxZ)) { p.sendMessage(msg("prefix") + " §c与领地 §e" + cx.name + " §c重叠！"); return; } } String name = a[1]; for (Claim cl : claims.values()) if (cl.name.equalsIgnoreCase(name)) { p.sendMessage(msg("prefix") + " §c领地名称已存在！"); return; } Claim cl = new Claim(nextId(), name, p.getUniqueId(), p.getName(), wname, minX, minZ, maxX, maxZ); claims.put(cl.id, cl); rebuildChunkIndex(); saveAll(); selections.remove(p.getUniqueId()); p.sendMessage(msg("prefix") + " §a领地 §e" + name + " §a创建成功！大小: §e" + dx + "x" + dz); p.playSound(p.getLocation(), Sound.ENTITY_PLAYER_LEVELUP, 1f, 1f); }

        private void doInvite(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim invite <玩家> [领地]"); return; } Player t = Bukkit.getPlayer(a[1]); if (t == null) { p.sendMessage(msg("player-not-found")); return; } Claim cl = a.length >= 3 ? findClaim(p.getUniqueId(), a[2]) : getClaimAt(p.getLocation(), null); if (cl == null || !cl.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } if (t.getUniqueId().equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c不能邀请自己！"); return; } if (cl.isMember(t.getUniqueId())) { p.sendMessage(msg("prefix") + " §e" + t.getName() + " §7已是成员！"); return; } invites.remove(t.getUniqueId()); invites.put(t.getUniqueId(), new ClaimInvite(cl, p.getUniqueId(), p.getName())); p.sendMessage(msg("prefix") + " §a已向 §e" + t.getName() + " §a发送邀请！§7(60秒)"); t.sendMessage(msg("prefix") + " §e" + p.getName() + " §a邀请你加入领地 §e" + cl.name); t.sendMessage("  §a/claim accept " + p.getName() + "  §c/claim deny " + p.getName()); t.playSound(t.getLocation(), Sound.BLOCK_NOTE_BLOCK_CHIME, 1f, 1.2f); }

        private void doKick(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim kick <玩家> [领地]"); return; } Claim cl = a.length >= 3 ? findClaim(p.getUniqueId(), a[2]) : getClaimAt(p.getLocation(), null); if (cl == null || !cl.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } Player t = Bukkit.getPlayer(a[1]); UUID uid = t != null ? t.getUniqueId() : null; if (uid == null) for (var e : cl.memberNames.entrySet()) if (e.getValue().equalsIgnoreCase(a[1])) { uid = e.getKey(); break; } if (uid == null) { p.sendMessage(msg("player-not-found")); return; } if (cl.removeMember(uid)) { saveAll(); p.sendMessage(msg("prefix") + " §c已移除成员"); } else p.sendMessage(msg("prefix") + " §c不是成员！"); }

        private void doRemove(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim remove <领地>"); return; } Claim cl = findClaim(p.getUniqueId(), a[1]); if (cl == null || (!cl.owner.equals(p.getUniqueId()) && !p.hasPermission("megaplugin.claim.admin"))) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } List<Claim> toRemove = new ArrayList<>(); collectAll(cl, toRemove); if (cl.isSubClaim()) { Claim parent = claims.get(cl.parentId); if (parent != null) parent.subClaims.remove(cl); } for (Claim sub : toRemove) claims.remove(sub.id); claims.remove(cl.id); rebuildChunkIndex(); saveAll(); p.sendMessage(msg("prefix") + " §c已删除 " + (toRemove.size() + 1) + " 个领地"); }

        private void doRename(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim rename <新名字> [领地]"); return; } Claim cl = a.length >= 3 ? findClaim(p.getUniqueId(), a[2]) : getClaimAt(p.getLocation(), null); if (cl == null || !cl.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } for (Claim cx : claims.values()) if (cx != cl && cx.name.equalsIgnoreCase(a[1])) { p.sendMessage(msg("prefix") + " §c名称已存在！"); return; } cl.name = a[1]; saveAll(); p.sendMessage(msg("prefix") + " §a已重命名！"); }
        private void doSetmsg(Player p, String[] a) { if (a.length < 3) { p.sendMessage(msg("prefix") + " §c用法: /claim setmsg <enter|leave> <消息>"); return; } Claim cl = a.length >= 4 ? findClaim(p.getUniqueId(), a[3]) : getClaimAt(p.getLocation(), null); if (cl == null || !cl.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } String msg = String.join(" ", Arrays.copyOfRange(a, 2, a.length)); if (a[1].equalsIgnoreCase("enter")) cl.enterMsg = msg; else if (a[1].equalsIgnoreCase("leave")) cl.leaveMsg = msg; else { p.sendMessage(msg("prefix") + " §c类型必须是 enter 或 leave"); return; } saveAll(); p.sendMessage(msg("prefix") + " §a已设置消息"); }
        private void doSell(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim sell <价格> [领地]"); return; } double price; try { price = Double.parseDouble(a[1]); } catch (Exception ex) { p.sendMessage(msg("invalid-number")); return; } Claim cl = a.length >= 3 ? findClaim(p.getUniqueId(), a[2]) : getClaimAt(p.getLocation(), null); if (cl == null || !cl.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } cl.price = price; saveAll(); p.sendMessage(msg("prefix") + " §a已" + (price > 0 ? "挂牌出售: §e" + price : "取消出售")); }
        private void doBuy(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim buy <领地>"); return; } Claim cl = null; for (Claim cx : claims.values()) if (cx.name.equalsIgnoreCase(a[1])) { cl = cx; break; } if (cl == null || cl.price <= 0) { p.sendMessage(msg("prefix") + " §c领地不存在或不出售！"); return; } if (cl.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c不能买自己的领地！"); return; } var eco = plugin.economy(); if (eco == null) { p.sendMessage(msg("prefix") + " §c经济系统未启用！"); return; } if (!eco.has(p.getUniqueId(), cl.price)) { p.sendMessage(msg("prefix") + " §c余额不足！需要 §e" + cl.price); return; } eco.withdraw(p.getUniqueId(), cl.price); Player old = Bukkit.getPlayer(cl.owner); if (old != null) eco.deposit(old.getUniqueId(), cl.price); else eco.deposit(cl.owner, cl.price); cl.owner = p.getUniqueId(); cl.ownerName = p.getName(); cl.memberFlags.clear(); cl.memberNames.clear(); cl.price = 0; saveAll(); p.sendMessage(msg("prefix") + " §a购买成功！"); p.playSound(p.getLocation(), Sound.ENTITY_PLAYER_LEVELUP, 1f, 1f); }

        private void doTp(Player p, String[] a) { Claim cl = a.length >= 2 ? findClaim(p.getUniqueId(), a[1]) : getClaimAt(p.getLocation(), null); if (cl == null) cl = playerClaims(p.getUniqueId()).stream().findFirst().orElse(null); if (cl == null) { p.sendMessage(msg("prefix") + " §c你没有领地！"); return; } final Claim fc = cl; Long cd = tpCooldowns.get(p.getUniqueId()); if (cd != null && System.currentTimeMillis() - cd < 30000) { p.sendMessage(msg("prefix") + " §c冷却中！剩余 §e" + (30 - (System.currentTimeMillis() - cd) / 1000) + "秒"); return; } Location dest = fc.spawn != null ? fc.spawn.clone() : new Location(Bukkit.getWorld(fc.world), (fc.minX + fc.maxX) / 2.0 + 0.5, Bukkit.getWorld(fc.world).getHighestBlockYAt((fc.minX + fc.maxX) / 2, (fc.minZ + fc.maxZ) / 2) + 1, (fc.minZ + fc.maxZ) / 2.0 + 0.5); TpTask old = tpTasks.get(p.getUniqueId()); if (old != null) Bukkit.getScheduler().cancelTask(old.taskId); final int[] count = {5}; Location origin = p.getLocation().clone(); int taskId = Bukkit.getScheduler().scheduleSyncRepeatingTask(plugin, () -> { TpTask cur = tpTasks.get(p.getUniqueId()); if (cur == null || !p.isOnline()) return; count[0]--; if (count[0] <= 0) { Bukkit.getScheduler().cancelTask(cur.taskId); tpTasks.remove(p.getUniqueId()); tpCooldowns.put(p.getUniqueId(), System.currentTimeMillis()); p.teleport(dest); p.sendMessage(msg("prefix") + " §a已传送到 §e" + fc.name); p.playSound(p.getLocation(), Sound.ENTITY_ENDERMAN_TELEPORT, 1f, 1f); } else p.sendMessage(msg("prefix") + " §7倒计时: §e" + count[0] + "§7秒..."); }, 0L, 20L); tpTasks.put(p.getUniqueId(), new TpTask(p.getUniqueId(), origin, taskId)); p.sendMessage(msg("prefix") + " §a5秒后传送，请不要移动！"); }
        private void doSetspawn(Player p, String[] a) { Claim cl = a.length >= 2 ? findClaim(p.getUniqueId(), a[1]) : getClaimAt(p.getLocation(), null); if (cl == null || !cl.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你必须在自己的领地内！"); return; } cl.spawn = p.getLocation().clone(); saveAll(); p.sendMessage(msg("prefix") + " §a传送点已设置！"); }
        private void doAdmin(Player p, String[] a) { if (!p.hasPermission("megaplugin.claim.admin")) { p.sendMessage(msg("no-permission")); return; } PlayerData d = pd(p.getUniqueId()); d.ignoreClaims = !d.ignoreClaims; p.sendMessage(msg("prefix") + " §a管理员模式: " + (d.ignoreClaims ? "§c关闭" : "§2正常")); }

        private void doInfo(Player p) { PlayerData d = pd(p.getUniqueId()); Claim c = getClaimAt(p.getLocation(), null); p.sendMessage("§8§m          §r §e§l领地信息 §8§m          "); if (c == null) { p.sendMessage("§7当前不在任何领地内"); } else { p.sendMessage("§7领地: §a" + c.name + " §8[" + c.id + "] §7主人: §e" + c.ownerName); p.sendMessage("§7范围: §f" + c.minX + "," + c.minZ + " ~ " + c.maxX + "," + c.maxZ + " §7大小: §e" + (c.maxX - c.minX + 1) + "x" + (c.maxZ - c.minZ + 1)); boolean isOwner = c.owner.equals(p.getUniqueId()), isMember = c.memberFlags.containsKey(p.getUniqueId()); p.sendMessage("§7身份: " + (isOwner ? "§a§l主人" : (isMember ? "§e成员" : "§7访客"))); Set<Flag> my = isOwner ? c.ownerFlags : (isMember ? c.memberFlags.get(p.getUniqueId()) : c.defaultFlags); StringBuilder sb = new StringBuilder(); if (my != null) for (Flag f : Flag.values()) sb.append(my.contains(f) ? "§a" : "§c").append(f.name).append(" "); p.sendMessage("§7" + sb); p.sendMessage("§7环境: §b"); for (OtherFlag of : OtherFlag.values()) { boolean on = c.otherFlags.getOrDefault(of, true); p.sendMessage("  " + (on ? "§a" : "§c") + of.name + (on ? " ✔" : " ✘")); } } p.sendMessage("§8§m                              "); }

        // ── 扩展/收缩 (委托到统一方法) ──
        private void doExpand(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim expand <格数>"); return; } int amount; try { amount = Integer.parseInt(a[1]); } catch (Exception ex) { p.sendMessage(msg("invalid-number")); return; } if (amount < 1 || amount > 16) { p.sendMessage(msg("prefix") + " §c格数 1~16！"); return; } doExpandDirect(p, getClaimAt(p.getLocation(), null), amount); }
        private void doShrink(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim shrink <格数>"); return; } int amount; try { amount = Integer.parseInt(a[1]); } catch (Exception ex) { p.sendMessage(msg("invalid-number")); return; } if (amount < 1 || amount > 16) { p.sendMessage(msg("prefix") + " §c格数 1~16！"); return; } doShrinkDirect(p, getClaimAt(p.getLocation(), null), amount); }

        // ── 租赁 ──
        private void doRent(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim rent <价格> [天数=7]"); return; } double price; try { price = Double.parseDouble(a[1]); } catch (Exception ex) { p.sendMessage(msg("invalid-number")); return; } int days = a.length >= 3 ? Integer.parseInt(a[2]) : 7; if (price < 0 || days < 1 || days > 90) { p.sendMessage(msg("prefix") + " §c参数无效！"); return; } Claim c = getClaimAt(p.getLocation(), null); if (c == null || !c.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你必须站在自己的领地内！"); return; } c.rentPrice = price; c.rentDays = days; c.rentedTo = null; c.rentedToName = null; c.rentEndTime = 0; saveAll(); p.sendMessage(msg("prefix") + " §a已" + (price > 0 ? "出租: §e" + price + "§a/§e" + days + "天" : "取消出租")); }
        private void doUnrent(Player p) { Claim c = getClaimAt(p.getLocation(), null); if (c == null || !c.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } c.rentPrice = 0; if (c.isRented()) { Player r = Bukkit.getPlayer(c.rentedTo); if (r != null) r.sendMessage(msg("prefix") + " §c租约被终止！"); c.removeMember(c.rentedTo); c.rentedTo = null; c.rentedToName = null; c.rentEndTime = 0; } saveAll(); p.sendMessage(msg("prefix") + " §7已取消出租"); }
        private void doLease(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim lease <领地名>"); return; } Claim c = null; for (Claim cl : claims.values()) if (cl.name.equalsIgnoreCase(a[1]) && cl.rentPrice > 0) { c = cl; break; } if (c == null || c.owner.equals(p.getUniqueId()) || c.isRented()) { p.sendMessage(msg("prefix") + " §c不可租用！"); return; } var eco = plugin.economy(); if (eco == null || !eco.has(p.getUniqueId(), c.rentPrice)) { p.sendMessage(msg("prefix") + " §c余额不足！"); return; } eco.withdraw(p.getUniqueId(), c.rentPrice); Player o = Bukkit.getPlayer(c.owner); if (o != null) eco.deposit(o.getUniqueId(), c.rentPrice); else eco.deposit(c.owner, c.rentPrice); c.rentedTo = p.getUniqueId(); c.rentedToName = p.getName(); c.rentEndTime = System.currentTimeMillis() + c.rentDays * 86400000L; c.addMember(p.getUniqueId(), p.getName()); saveAll(); p.sendMessage(msg("prefix") + " §a已租用 §e" + c.name + " §a！"); if (o != null) o.sendMessage(msg("prefix") + " §a" + p.getName() + " 租用了 §e" + c.name); }
        private void doEvict(Player p, String[] a) { Claim c = a.length >= 2 ? findClaim(p.getUniqueId(), a[1]) : getClaimAt(p.getLocation(), null); if (c == null || !c.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c不是你的领地！"); return; } if (!c.isRented()) { p.sendMessage(msg("prefix") + " §7没有租客"); return; } Player r = Bukkit.getPlayer(c.rentedTo); if (r != null) r.sendMessage(msg("prefix") + " §c你被驱逐了！"); c.removeMember(c.rentedTo); c.rentedTo = null; c.rentedToName = null; c.rentEndTime = 0; saveAll(); p.sendMessage(msg("prefix") + " §a已驱逐"); }
        private void doSetSign(Player p) { Block b = p.getTargetBlockExact(5); if (b == null || !(b.getState() instanceof Sign)) { p.sendMessage(msg("prefix") + " §c请看向告示牌！"); return; } Claim c = getClaimAt(b.getLocation(), null); if (c == null || !c.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } c.signLocation = b.getLocation().clone(); Sign sign = (Sign) b.getState(); sign.setLine(0, "§6§l[领地]"); sign.setLine(1, "§a" + c.name.substring(0, Math.min(c.name.length(), 15))); sign.setLine(2, "§e" + c.ownerName); sign.setLine(3, "§7" + (c.maxX - c.minX + 1) + "x" + (c.maxZ - c.minZ + 1)); sign.update(); saveAll(); p.sendMessage(msg("prefix") + " §a标志牌已设置！"); }

        private void doAccept(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim accept <玩家>"); return; } ClaimInvite inv = invites.get(p.getUniqueId()); if (inv == null || inv.expired()) { invites.remove(p.getUniqueId()); p.sendMessage(msg("prefix") + " §c没有待处理的邀请！"); return; } if (!inv.inviterName.equalsIgnoreCase(a[1])) { p.sendMessage(msg("prefix") + " §c邀请来自 §e" + inv.inviterName + " §c不是 §e" + a[1]); return; } invites.remove(p.getUniqueId()); inv.claim.addMember(p.getUniqueId(), p.getName()); saveAll(); p.sendMessage(msg("prefix") + " §a已加入领地 §e" + inv.claim.name); p.playSound(p.getLocation(), Sound.ENTITY_PLAYER_LEVELUP, 1f, 1f); Player inviter = Bukkit.getPlayer(inv.inviter); if (inviter != null) inviter.sendMessage(msg("prefix") + " §a" + p.getName() + " 接受了邀请！"); }
        private void doDeny(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim deny <玩家>"); return; } ClaimInvite inv = invites.get(p.getUniqueId()); if (inv == null || inv.expired()) { invites.remove(p.getUniqueId()); p.sendMessage(msg("prefix") + " §c没有待处理的邀请！"); return; } if (!inv.inviterName.equalsIgnoreCase(a[1])) { p.sendMessage(msg("prefix") + " §c邀请来自 §e" + inv.inviterName); return; } invites.remove(p.getUniqueId()); p.sendMessage(msg("prefix") + " §c已拒绝"); Player inviter = Bukkit.getPlayer(inv.inviter); if (inviter != null) inviter.sendMessage(msg("prefix") + " §c" + p.getName() + " 拒绝了邀请"); }
        private void doInvites(Player p) { ClaimInvite inv = invites.get(p.getUniqueId()); if (inv == null || inv.expired()) { invites.remove(p.getUniqueId()); p.sendMessage(msg("prefix") + " §7没有待处理的邀请"); return; } int sec = Math.max(0, (int) ((inv.expireTime - System.currentTimeMillis()) / 1000)); p.sendMessage(msg("prefix") + " §e" + inv.inviterName + " §7邀请你加入: §a" + inv.claim.name + " §7(" + sec + "秒)"); }
        private void doGive(Player p, String[] a) { if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim give <玩家> [领地]"); return; } Player t = Bukkit.getPlayer(a[1]); if (t == null) { p.sendMessage(msg("player-not-found")); return; } Claim c = a.length >= 3 ? findClaim(p.getUniqueId(), a[2]) : getClaimAt(p.getLocation(), null); if (c == null || !c.owner.equals(p.getUniqueId()) || c.isSubClaim()) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } c.owner = t.getUniqueId(); c.ownerName = t.getName(); for (Claim sub : c.subClaims) { sub.owner = t.getUniqueId(); sub.ownerName = t.getName(); } saveAll(); p.sendMessage(msg("prefix") + " §a已转让给 §e" + t.getName()); t.sendMessage(msg("prefix") + " §a获得了领地 §e" + c.name); }

        private void doSubCreate(Player p, String[] a) { Claim parent = getClaimAt(p.getLocation(), null); if (parent == null || !parent.owner.equals(p.getUniqueId()) || parent.isSubClaim()) { p.sendMessage(msg("prefix") + " §c你必须站在自己的主领地内！"); return; } if (a.length < 2) { p.sendMessage(msg("prefix") + " §c用法: /claim subcreate <名字>"); return; } if (parent.subClaims.size() >= 3) { p.sendMessage(msg("prefix") + " §c最多3个子领地！"); return; } Location[] sel = selections.get(p.getUniqueId()); if (sel == null || sel[0] == null || sel[1] == null) { p.sendMessage(msg("prefix") + " §c请先选区！"); return; } int minX = Math.min(sel[0].getBlockX(), sel[1].getBlockX()), maxX = Math.max(sel[0].getBlockX(), sel[1].getBlockX()), minZ = Math.min(sel[0].getBlockZ(), sel[1].getBlockZ()), maxZ = Math.max(sel[0].getBlockZ(), sel[1].getBlockZ()); if (minX < parent.minX || maxX > parent.maxX || minZ < parent.minZ || maxZ > parent.maxZ) { p.sendMessage(msg("prefix") + " §c子领地必须在主领地内！"); return; } for (Claim o : parent.subClaims) if (!(maxX < o.minX || minX > o.maxX || maxZ < o.minZ || minZ > o.maxZ)) { p.sendMessage(msg("prefix") + " §c与子领地重叠！"); return; } Claim sub = new Claim(nextId(), a[1], p.getUniqueId(), p.getName(), parent.world, minX, minZ, maxX, maxZ); sub.parentId = parent.id; sub.minY = parent.minY; sub.maxY = parent.maxY; parent.subClaims.add(sub); claims.put(sub.id, sub); rebuildChunkIndex(); saveAll(); p.sendMessage(msg("prefix") + " §a子领地已创建！"); }

        private void doAll(Player p, String[] a) { int page = 1; if (a.length >= 2) try { page = Integer.parseInt(a[1]); } catch (Exception ignored) {} var all = claims.values().stream().filter(c -> !c.isSubClaim()).toList(); int tp = Math.max(1, (all.size() + 9) / 10); page = Math.max(1, Math.min(page, tp)); p.sendMessage("§8§m          §r §e§l全部领地 §7(第" + page + "/" + tp + "页) §8§m          "); int start = (page - 1) * 10, end = Math.min(start + 10, all.size()); for (int i = start; i < end; i++) { Claim c = all.get(i); String sell = c.price > 0 ? " §a[售 §6" + c.price + "§a]" : ""; p.sendMessage(" §a" + c.name + sell + " §7主人: §e" + c.ownerName + " §7成员: §f" + c.memberFlags.size()); } }
        private void doScreen(Player p, String[] a) { doScreenDirect(p, a.length >= 2 ? String.join(" ", Arrays.copyOfRange(a, 1, a.length)).toLowerCase() : ""); }

        private void doFlag(Player p, String[] a) { if (a.length < 4) { p.sendMessage(msg("prefix") + " §c用法: /claim flag <领地> <成员> <Flag>"); return; } Claim c = findClaim(p.getUniqueId(), a[1]); if (c == null || !c.owner.equals(p.getUniqueId())) { p.sendMessage(msg("prefix") + " §c你没有权限！"); return; } UUID uid = null; Player tp = Bukkit.getPlayer(a[2]); if (tp != null) uid = tp.getUniqueId(); else { for (var e : c.memberNames.entrySet()) if (e.getValue().equalsIgnoreCase(a[2])) { uid = e.getKey(); break; } } if (uid == null || !c.isMember(uid)) { p.sendMessage(msg("prefix") + " §c该玩家不是成员！"); return; } Flag flag = null; for (Flag f : Flag.values()) if (f.name().equalsIgnoreCase(a[3])) { flag = f; break; } if (flag == null) { p.sendMessage(msg("prefix") + " §c未知Flag"); return; } c.toggleMemberFlag(uid, flag); saveAll(); p.sendMessage(msg("prefix") + " §a已切换 §e" + a[2] + " §a的 §e" + flag.name); }

        private void showHelp(Player p) { p.sendMessage("§8§m          §r §a§l领地系统 v5 §8§m          "); p.sendMessage(" §7/claim §e- 打开领地菜单 §7/claim create <名字> §e- 创建领地"); p.sendMessage(" §7/claim expand|shrink <格> §e- 扩展/收缩 §7/claim invite|kick <玩家> §e- 邀请/移除"); p.sendMessage(" §7/claim tp [领地] §e- 传送 §7/claim sell|rent <价格> §e- 出售/出租"); p.sendMessage(" §7/claim all|screen §e- 查看/搜索 §7/claim info §e- 信息"); }
    }

    class ClaimTab implements TabCompleter {
        public List<String> onTabComplete(CommandSender s, Command c, String l, String[] a) { if (!(s instanceof Player p)) return List.of(); List<String> cmds = List.of("create", "subcreate", "expand", "shrink", "invite", "accept", "deny", "invites", "kick", "remove", "give", "rename", "setmsg", "sell", "buy", "tp", "setspawn", "admin", "list", "all", "map", "shop", "screen", "flag", "info", "rent", "unrent", "lease", "evict", "setsign"); if (a.length == 1) return cmds.stream().filter(x -> x.startsWith(a[0].toLowerCase())).toList(); if (a.length == 2 && List.of("invite", "kick", "give", "accept", "deny").contains(a[0].toLowerCase())) return Bukkit.getOnlinePlayers().stream().map(Player::getName).filter(x -> x.toLowerCase().startsWith(a[1].toLowerCase())).toList(); if (a.length == 2 && List.of("remove", "rename", "tp", "flag").contains(a[0].toLowerCase())) return playerClaims(p.getUniqueId()).stream().map(cl -> cl.name).filter(x -> x.toLowerCase().startsWith(a[1].toLowerCase())).toList(); if (a.length == 2 && a[0].equalsIgnoreCase("buy")) return claims.values().stream().filter(cl -> cl.price > 0).map(cl -> cl.name).filter(x -> x.toLowerCase().startsWith(a[1].toLowerCase())).toList(); return List.of(); }
    }

