    private ItemStack rentButton(Claim c) { if (c.isRented()) return createItem(Material.CLOCK, "§3§l租赁信息", "§7租客: §e" + c.rentedToName, "§7到期: §e" + formatTimeLong(c.rentEndTime), "§c点击驱逐"); if (c.rentPrice > 0) return createItem(Material.EMERALD, "§2§l出租中", "§7租金: §e" + c.rentPrice + " §7/ §e" + c.rentDays + "天", "§7点击取消出租"); if (c.price > 0) return createItem(Material.GOLD_INGOT, "§2§l出售中", "§7价格: §e" + c.price, "§7点击取消出售"); return createItem(Material.GOLD_NUGGET, "§2§l出租/出售", "§7/claim rent <价格>", "§7/claim sell <价格>"); }

