    private void openMapGui(Player p) { Inventory inv = Bukkit.createInventory(null, 54, GUI_MAP); Location loc = p.getLocation(); int cx = loc.getBlockX() >> 4, cz = loc.getBlockZ() >> 4; for (int row = 0; row < 6; row++) for (int col = 0; col < 9; col++) { int wx = (cx - 4 + col) << 4, wz = (cz - 2 + row) << 4; int slot = row * 9 + col; if (row == 2 && col == 4) { inv.setItem(slot, createItem(Material.PLAYER_HEAD, "§a§l你")); continue; } Claim found = getClaimAt(new Location(loc.getWorld(), wx, loc.getY(), wz), null); inv.setItem(slot, found != null ? createItem(found.owner.equals(p.getUniqueId()) ? Material.LIME_WOOL : Material.RED_WOOL, (found.owner.equals(p.getUniqueId()) ? "§a" : "§c") + found.name) : createItem(Material.GREEN_STAINED_GLASS_PANE, "§7荒野")); } inv.setItem(49, createItem(Material.COMPASS, "§d§l刷新")); inv.setItem(53, createItem(Material.BARRIER, "§c§l关闭")); p.openInventory(inv); }

    private void openBuyGui(Player p) { Inventory inv = Bukkit.createInventory(null, 54, GUI_BUY); int slot = 0; for (Claim c : claims.values()) { if (c.price <= 0 || slot >= 45) continue; inv.setItem(slot++, createItem(Material.GRASS_BLOCK, "§a§l" + c.name, "§7主人: §e" + c.ownerName, "§7价格: §6" + c.price, "§7点击购买")); } if (slot == 0) inv.setItem(13, createItem(Material.BARRIER, "§c暂无出售中的领地")); inv.setItem(53, createItem(Material.BARRIER, "§c§l关闭")); fillGlass(inv, 0, 54); p.openInventory(inv); }

